if (isset($_POST['admin_sensitive_unlock_ajax'])) {
    header('Content-Type: application/json; charset=utf-8');

    if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
        http_response_code(403);
        echo json_encode([
            'ok' => false,
            'message' => admin_t($messages, 'login_error', 'Login failed. Check your credentials.'),
        ]);
        exit;
    }

    $password = (string)($_POST['sensitive_password'] ?? '');
    if (!admin_unlock_sensitive_routes($password)) {
        http_response_code(422);
        echo json_encode([
            'ok' => false,
            'message' => admin_t($messages, 'settings_sensitive_unlock_error', 'Incorrect password.'),
        ]);
        exit;
    }

    echo json_encode([
        'ok' => true,
        'message' => admin_t($messages, 'settings_sensitive_unlock_success', 'Access unlocked until logout.'),
    ]);
    exit;
}

if (isset($_POST['admin_update_help_topic_ajax'])) {
    header('Content-Type: application/json; charset=utf-8');

    if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
        http_response_code(403);
        echo json_encode([
            'ok' => false,
            'message' => admin_t($messages, 'login_error', 'Login failed. Check your credentials.'),
        ]);
        exit;
    }

    if (!$adminHelpModalCanEdit) {
        http_response_code(403);
        echo json_encode([
            'ok' => false,
            'message' => admin_t($messages, 'help_modal_edit_locked', 'Unlock Settings access first to edit help content.'),
        ]);
        exit;
    }

    $topicId = (int)($_POST['topic_id'] ?? 0);
    $answerHtml = (string)($_POST['answer_html'] ?? '');
    $saveResult = admin_update_help_topic_answer($db, $topicId, $answerHtml);

    if (empty($saveResult['ok']) || !is_array($saveResult['topic'] ?? null)) {
        http_response_code(422);
        echo json_encode([
            'ok' => false,
            'message' => admin_t($messages, 'help_save_error', (string)($saveResult['message'] ?? 'Unable to save help topic.')),
        ]);
        exit;
    }

    $topicRow = (array)$saveResult['topic'];
    $audienceOptions = admin_help_topic_audience_options();
    $audienceCode = admin_help_topic_normalize_audience((string)($topicRow['audience_code'] ?? 'all'));
    $audienceLabel = (string)($audienceOptions[$audienceCode] ?? $audienceCode);
    $topicAnswerHtml = (string)($topicRow['answer_html'] ?? '');
    $searchText = trim(implode(' ', [
        (string)($topicRow['question'] ?? ''),
        (string)($topicRow['keywords'] ?? ''),
        trim(strip_tags($topicAnswerHtml)),
        $audienceLabel,
    ]));
    if (function_exists('mb_strtolower')) {
        $searchText = mb_strtolower($searchText);
    } else {
        $searchText = strtolower($searchText);
    }

    admin_activity_log(
        $db,
        0,
        (int)($adminUser['id'] ?? 0),
        'help_topic_inline_update',
        'Updated help modal topic #' . $topicId . ': ' . (string)($topicRow['question'] ?? ''),
        $requestIp
    );

    echo json_encode([
        'ok' => true,
        'message' => admin_t($messages, 'help_save_success', 'Help topic saved successfully.'),
        'topic' => [
            'id' => (int)($topicRow['id'] ?? 0),
            'question' => (string)($topicRow['question'] ?? ''),
            'answer_html' => $topicAnswerHtml,
            'audience_code' => $audienceCode,
            'audience_label' => $audienceLabel,
            'keywords' => (string)($topicRow['keywords'] ?? ''),
            'search_text' => $searchText,
        ],
    ]);
    exit;
}

if (isset($_POST['admin_save_personal_notes_ajax'])) {
    header('Content-Type: application/json; charset=utf-8');

    if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
        http_response_code(403);
        echo json_encode([
            'ok' => false,
            'message' => admin_t($messages, 'login_error', 'Login failed. Check your credentials.'),
        ]);
        exit;
    }

    if ((int)($adminUser['id'] ?? 0) <= 0) {
        http_response_code(403);
        echo json_encode([
            'ok' => false,
            'message' => admin_t($messages, 'login_error', 'Login failed. Check your credentials.'),
        ]);
        exit;
    }

    if (!$adminPersonalNotesAvailable) {
        http_response_code(409);
        echo json_encode([
            'ok' => false,
            'message' => admin_t($messages, 'settings_notes_sql_required', 'SQL migration is required before administrator notes can be saved.'),
        ]);
        exit;
    }

    $saveNotesResult = admin_save_personal_notes(
        $db,
        (int)($adminUser['id'] ?? 0),
        (string)($_POST['personal_notes_html'] ?? '')
    );

    if (empty($saveNotesResult['ok']) || !is_array($saveNotesResult['admin_user'] ?? null)) {
        http_response_code(422);
        echo json_encode([
            'ok' => false,
            'message' => admin_t($messages, 'settings_notes_save_error', (string)($saveNotesResult['message'] ?? 'Unable to save administrator notes.')),
        ]);
        exit;
    }

    $savedAdminUser = (array)$saveNotesResult['admin_user'];
    echo json_encode([
        'ok' => true,
        'message' => admin_t($messages, 'settings_notes_saved', 'Your administrator notes have been saved automatically.'),
        'notes_html' => (string)($savedAdminUser['personal_notes_html'] ?? ''),
        'updated_at' => (string)($savedAdminUser['updated_at'] ?? ''),
    ]);
    exit;
}

