            $deleteCustomerResult = admin_delete_customer_account(
                $db,
                $selectedCustomerId,
                (int)($adminUser['id'] ?? 0),
                $requestIp
            );

            if (!empty($deleteCustomerResult['ok'])) {
                header('Location: /admin/?page=users&deleted_user=1');
                exit;
            }

            $pageAlert = (string)($deleteCustomerResult['message'] ?? '');
            $pageAlertType = 'danger';
        }
    }

    if ($selectedCustomerId > 0 && isset($_POST['admin_delete_customer_wallet_assignment'])) {
        if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
            $pageAlert = admin_t($messages, 'login_error', 'Login failed. Check your credentials.');
            $pageAlertType = 'danger';
        } else {
            $deleteWalletResult = admin_delete_customer_wallet_assignment(
                $db,
                $selectedCustomerId,
                (int)($_POST['wallet_assignment_id'] ?? 0),
                (int)($adminUser['id'] ?? 0),
                $requestIp
            );
            $pageAlert = (string)($deleteWalletResult['message'] ?? admin_t($messages, 'customer_wallet_delete_error', 'Unable to remove wallet assignment.'));
            $pageAlertType = !empty($deleteWalletResult['ok']) ? 'success' : 'danger';
        }
    }

    if ($selectedCustomerId > 0 && isset($_POST['admin_delete_customer_bank_assignment'])) {
        if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
            $pageAlert = admin_t($messages, 'login_error', 'Login failed. Check your credentials.');
            $pageAlertType = 'danger';
        } else {
            $deleteBankResult = admin_delete_customer_bank_assignment(
                $db,
                $selectedCustomerId,
                (int)($_POST['bank_account_assignment_id'] ?? 0),
                (int)($adminUser['id'] ?? 0),
                $requestIp
            );
            $pageAlert = (string)($deleteBankResult['message'] ?? admin_t($messages, 'customer_bank_delete_error', 'Unable to remove bank account assignment.'));
            $pageAlertType = !empty($deleteBankResult['ok']) ? 'success' : 'danger';
        }
    }

    if ($selectedCustomerId > 0 && isset($_POST['admin_delete_customer_activity_entry'])) {
        if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
            $pageAlert = admin_t($messages, 'login_error', 'Login failed. Check your credentials.');
            $pageAlertType = 'danger';
        } else {
            $deleteActivityResult = admin_delete_customer_activity_entry(
                $db,
                $selectedCustomerId,
                (int)($_POST['activity_id'] ?? 0),
                (int)($adminUser['id'] ?? 0),
                $requestIp
            );
            $pageAlert = (string)($deleteActivityResult['message'] ?? admin_t($messages, 'customer_activity_delete_error', 'Unable to remove history entry.'));
            $pageAlertType = !empty($deleteActivityResult['ok']) ? 'success' : 'danger';
        }
    }

    if ($selectedCustomerId > 0 && isset($_POST['admin_customer_group_invite_action'])) {
        if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
            $pageAlert = admin_t($messages, 'login_error', 'Login failed. Check your credentials.');
            $pageAlertType = 'danger';
        } else {
            $groupInviteResult = admin_customer_group_chat_invite_response(
                $db,
                $selectedCustomerId,
                (int)($_POST['conversation_id'] ?? 0),
                (string)($_POST['invite_decision'] ?? ''),
                (int)($adminUser['id'] ?? 0),
                $requestIp
            );
            $pageAlert = (string)($groupInviteResult['message'] ?? admin_t($messages, 'customer_group_chat_action_error', 'Unable to update the group invitation.'));
            $pageAlertType = !empty($groupInviteResult['ok']) ? 'success' : 'danger';
        }
    }

    if ($selectedCustomerId > 0 && isset($_POST['admin_customer_leave_group_chat'])) {
        if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
            $pageAlert = admin_t($messages, 'login_error', 'Login failed. Check your credentials.');
            $pageAlertType = 'danger';
        } else {
            $leaveGroupResult = admin_customer_leave_group_chat(
                $db,
                $selectedCustomerId,
                (int)($_POST['conversation_id'] ?? 0),
                (int)($adminUser['id'] ?? 0),
                $requestIp
            );
            $pageAlert = (string)($leaveGroupResult['message'] ?? admin_t($messages, 'customer_group_chat_leave_error', 'Unable to leave the group chat.'));
            $pageAlertType = !empty($leaveGroupResult['ok']) ? 'success' : 'danger';
        }
    }

    if ($selectedCustomerId > 0 && isset($_POST['admin_customer_delete_group_chat'])) {
        if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
            $pageAlert = admin_t($messages, 'login_error', 'Login failed. Check your credentials.');
            $pageAlertType = 'danger';
        } else {
            $deleteGroupResult = admin_customer_delete_group_chat(
                $db,
                $selectedCustomerId,
                (int)($_POST['conversation_id'] ?? 0),
                (int)($adminUser['id'] ?? 0),
                $requestIp
            );
            $pageAlert = (string)($deleteGroupResult['message'] ?? admin_t($messages, 'customer_group_chat_delete_error', 'Unable to delete the group chat.'));
            $pageAlertType = !empty($deleteGroupResult['ok']) ? 'success' : 'danger';
        }
    }

    if ($selectedCustomerId > 0) {
        $selectedCustomer = admin_customer_detail_row($db, $selectedCustomerId);
        if ($selectedCustomer) {
            $selectedCustomerSummary = admin_customer_management_summary($db, $selectedCustomerId);
            $selectedCustomerOrders = admin_customer_order_rows($db, $selectedCustomerId);
            $selectedCustomerPayments = admin_customer_payment_activity($db, $selectedCustomerId);
            $selectedCustomerGroupChats = admin_customer_group_chat_rows($db, $selectedCustomerId);
            $selectedCustomerProviderVisibility = admin_customer_provider_visibility_rows($db, $selectedCustomerId);
            $selectedCustomerWallets = admin_customer_wallet_rows($db, $selectedCustomerId);
            $selectedCustomerBankAccounts = admin_customer_bank_rows($db, $selectedCustomerId);
            $selectedCustomerActivity = admin_customer_activity_rows($db, $selectedCustomerId);

            if ((int)($selectedCustomerSummary['orders_total'] ?? 0) === 0) {
                $userQuickOrderVisibleProviderIds = admin_customer_visible_provider_ids($db, $selectedCustomerId);
                $userQuickOrderProviders = array_values(array_filter(
                    admin_product_provider_rows($db),
                    static function (array $providerRow) use ($userQuickOrderVisibleProviderIds): bool {
                        $providerId = (int)($providerRow['id'] ?? 0);
                        return $providerId > 0 && in_array($providerId, $userQuickOrderVisibleProviderIds, true);
                    }
                ));
                $userQuickOrderProducts = array_values(array_filter(
                    admin_product_active_rows($db),
                    static function (array $productRow) use ($userQuickOrderVisibleProviderIds): bool {
                        $providerId = (int)($productRow['provider_id'] ?? 0);
                        return $providerId > 0
                            && in_array($providerId, $userQuickOrderVisibleProviderIds, true)
                            && admin_order_product_can_extend($productRow);
                    }
                ));
                foreach ($userQuickOrderProducts as $userQuickOrderProduct) {
                    $providerId = (int)($userQuickOrderProduct['provider_id'] ?? 0);
                    if ($providerId <= 0) {
                        continue;
                    }
                    if (!isset($userQuickOrderProductsByProvider[$providerId])) {
                        $userQuickOrderProductsByProvider[$providerId] = [];
                    }
                    $userQuickOrderProductsByProvider[$providerId][] = $userQuickOrderProduct;
                }
                $userQuickOrderAvailable = !empty($userQuickOrderProviders) && !empty($userQuickOrderProducts);
            }
        }
    }

    if (isset($_POST['admin_create_user_quick_order']) && $selectedCustomerId > 0) {
        $userQuickOrderState = [
            'provider_id' => (int)($_POST['provider_id'] ?? 0),
            'product_id' => (int)($_POST['product_id'] ?? 0),
            'customer_note' => trim((string)($_POST['customer_note'] ?? '')),
        ];

        if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
            $pageAlert = admin_t($messages, 'login_error', 'Login failed. Check your credentials.');
            $pageAlertType = 'danger';
        } elseif (!$selectedCustomer || (int)($selectedCustomerSummary['orders_total'] ?? 0) > 0 || !$userQuickOrderAvailable) {
            $pageAlert = admin_t($messages, 'order_create_error', 'Unable to create order.');
            $pageAlertType = 'danger';
        } else {
            $createResult = admin_create_order($db, [
                'customer_id' => $selectedCustomerId,
                'product_id' => $userQuickOrderState['product_id'],
                'customer_note' => $userQuickOrderState['customer_note'],
                'has_delivery_link' => '0',
                'delivery_link' => '',
            ]);

            if (!empty($createResult['ok'])) {
                header('Location: /admin/?page=users&customer_id=' . $selectedCustomerId . '&created_order=1');
                exit;
            }

            $pageAlert = (string)($createResult['message'] ?? admin_t($messages, 'order_create_error', 'Unable to create order.'));
            $pageAlertType = 'danger';
        }
    }
}

if ($route === 'payments') {
    $cryptoPaymentsVisibleInPayments = !empty($appSettings['crypto_payments_enabled']);
    $bankTransfersVisibleInPayments = admin_bank_transfers_enabled($appSettings);
    $paymentFilterCustomerId = isset($_GET['customer_id']) ? (int)$_GET['customer_id'] : 0;
    if ($paymentFilterCustomerId > 0) {
        $paymentFilterCustomer = admin_customer_basic_row($db, $paymentFilterCustomerId);
        if (!$paymentFilterCustomer) {
            $paymentFilterCustomerId = 0;
        }
    }

    $paymentScope = strtolower(trim((string)($_GET['payment_scope'] ?? 'all')));
    if (!in_array($paymentScope, ['open', 'new', 'review', 'approved', 'archived', 'all'], true)) {
        $paymentScope = 'all';
    }

    $paymentTypeFilter = strtolower(trim((string)($_GET['payment_type_filter'] ?? '')));
    if (!in_array($paymentTypeFilter, ['', 'crypto', 'bank'], true)) {
        $paymentTypeFilter = '';
    }
    if (!$cryptoPaymentsVisibleInPayments && $paymentTypeFilter === 'crypto') {
        $paymentTypeFilter = '';
    }
    if (!$bankTransfersVisibleInPayments && $paymentTypeFilter === 'bank') {
        $paymentTypeFilter = '';
    }

    $buildPaymentsListUrl = static function (array $overrides = []) use ($paymentFilterCustomerId, $paymentScope, $paymentTypeFilter): string {
        $query = [
            'page' => 'payments',
            'customer_id' => $paymentFilterCustomerId > 0 ? $paymentFilterCustomerId : null,
            'payment_scope' => $paymentScope !== 'all' ? $paymentScope : null,
            'payment_type_filter' => $paymentTypeFilter !== '' ? $paymentTypeFilter : null,
        ];

        foreach ($overrides as $key => $value) {
            $query[$key] = $value;
        }

        foreach ($query as $key => $value) {
            if ($value === null || $value === '') {
                unset($query[$key]);
            }
        }

        return '/admin/?' . http_build_query($query);
    };

    $paymentEditorType = strtolower(trim((string)($_GET['payment_type'] ?? '')));
    if (!in_array($paymentEditorType, ['crypto', 'crypto_topup', 'bank'], true)) {
        $paymentEditorType = '';
    }
    if (!$bankTransfersVisibleInPayments && $paymentEditorType === 'bank') {
        $paymentEditorType = '';
    }
    $paymentEditorId = isset($_GET['payment_id']) ? (int)$_GET['payment_id'] : 0;

    if (isset($_POST['admin_payment_quick_action_ajax'])) {
        header('Content-Type: application/json; charset=utf-8');

        $paymentEditorType = strtolower(trim((string)($_POST['payment_type'] ?? $paymentEditorType)));
        if (!in_array($paymentEditorType, ['crypto', 'crypto_topup', 'bank'], true)) {
            $paymentEditorType = '';
        }
        if (!$bankTransfersVisibleInPayments && $paymentEditorType === 'bank') {
            $paymentEditorType = '';
        }
        $paymentEditorId = (int)($_POST['payment_id'] ?? $paymentEditorId);

        if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
            http_response_code(403);
            echo json_encode([
                'ok' => false,
                'message' => admin_t($messages, 'login_error', 'Login failed. Check your credentials.'),
            ]);
            exit;
        }

        if ($paymentEditorType === '') {
            http_response_code(422);
            echo json_encode([
                'ok' => false,
                'message' => admin_t($messages, 'payment_bank_disabled_hidden', 'Bank transfer payments are currently hidden.'),
            ]);
            exit;
        }

        $quickActionResult = admin_payment_apply_quick_action(
            $db,
            $paymentEditorType,
            $paymentEditorId,
            (string)($_POST['quick_action'] ?? ''),
            (int)($adminUser['id'] ?? 0),
            $requestIp
        );

        if (empty($quickActionResult['ok'])) {
            http_response_code(422);
            echo json_encode([
                'ok' => false,
                'message' => (string)($quickActionResult['message'] ?? admin_t($messages, 'payment_save_error', 'Unable to save payment request.')),
            ]);
            exit;
        }

        $orderPayload = null;
        $acceptedOrderId = (int)($quickActionResult['order_id'] ?? 0);
        if ($acceptedOrderId > 0) {
            $acceptedOrderRow = admin_topbar_notification_order_row_by_id($db, $acceptedOrderId);
            if (is_array($acceptedOrderRow)) {
                $acceptedOrderStatusVisual = admin_order_status_visual($acceptedOrderRow);
                $acceptedOrderHandle = trim((string)($acceptedOrderRow['public_handle'] ?? ''));
                $acceptedOrderPaymentType = (int)($acceptedOrderRow['crypto_payment_id'] ?? 0) > 0
                    ? 'crypto'
                    : ((int)($acceptedOrderRow['bank_payment_id'] ?? 0) > 0 ? 'bank' : '');
                $acceptedOrderPaymentId = $acceptedOrderPaymentType === 'crypto'
                    ? (int)($acceptedOrderRow['crypto_payment_id'] ?? 0)
                    : (int)($acceptedOrderRow['bank_payment_id'] ?? 0);
                $acceptedOrderWalletAddress = trim((string)($acceptedOrderRow['wallet_address'] ?? ''));
                $acceptedOrderWalletLabel = trim((string)($acceptedOrderRow['wallet_label'] ?? ''));
                $acceptedOrderWalletAssetCode = trim((string)($acceptedOrderRow['wallet_asset_code'] ?? ''));
                $acceptedOrderWalletNetworkCode = trim((string)($acceptedOrderRow['wallet_network_code'] ?? ''));
                $orderPayload = [
                    'id' => $acceptedOrderId,
                    'customer_id' => (int)($acceptedOrderRow['customer_id'] ?? 0),
                    'customer_email' => (string)($acceptedOrderRow['customer_email'] ?? ''),
                    'customer_handle' => $acceptedOrderHandle,
                    'order_url' => '/admin/?page=orders&order_id=' . $acceptedOrderId,
                    'payment_url' => ($acceptedOrderPaymentType !== '' && $acceptedOrderPaymentId > 0)
                        ? '/admin/?page=payments&payment_type=' . rawurlencode($acceptedOrderPaymentType) . '&payment_id=' . $acceptedOrderPaymentId
                        : '',
                    'status_icon' => (string)($acceptedOrderStatusVisual['icon'] ?? 'bi bi-arrow-repeat'),
                    'status_class' => (string)($acceptedOrderStatusVisual['class'] ?? 'admin-order-status-icon--awaiting-activation'),
                    'wallet_address_compact' => $acceptedOrderWalletAddress !== '' ? admin_compact_wallet_address($acceptedOrderWalletAddress, 8, 5) : '',
                    'wallet_explorer_url' => $acceptedOrderWalletAddress !== '' ? admin_crypto_wallet_explorer_url($acceptedOrderWalletAssetCode, $acceptedOrderWalletNetworkCode, $acceptedOrderWalletAddress) : '',
                    'wallet_label' => $acceptedOrderWalletLabel,
                ];
            } else {
                $fallbackOrderRow = admin_order_find($db, $acceptedOrderId);
                if (is_array($fallbackOrderRow)) {
                    $fallbackOrderStatusVisual = admin_order_status_visual($fallbackOrderRow);
                    $acceptedOrderHandle = trim((string)($fallbackOrderRow['public_handle'] ?? ''));
                    $orderPayload = [
                        'id' => $acceptedOrderId,
                        'customer_id' => (int)($fallbackOrderRow['customer_id'] ?? 0),
                        'customer_email' => (string)($fallbackOrderRow['customer_email'] ?? ''),
                        'customer_handle' => $acceptedOrderHandle,
                        'order_url' => '/admin/?page=orders&order_id=' . $acceptedOrderId,
                        'payment_url' => '',
                        'status_icon' => (string)($fallbackOrderStatusVisual['icon'] ?? 'bi bi-arrow-repeat'),
                        'status_class' => (string)($fallbackOrderStatusVisual['class'] ?? 'admin-order-status-icon--awaiting-activation'),
                        'wallet_address_compact' => '',
                        'wallet_explorer_url' => '',
                        'wallet_label' => '',
                    ];
                }
            }
        }

        echo json_encode([
            'ok' => true,
            'message' => (string)($quickActionResult['message'] ?? admin_t($messages, 'payment_save_success', 'Payment request saved successfully.')),
            'payment_id' => $paymentEditorId,
            'order' => $orderPayload,
        ]);
        exit;
    }

    if (isset($_POST['admin_payment_quick_action'])) {
        $paymentEditorType = strtolower(trim((string)($_POST['payment_type'] ?? $paymentEditorType)));
        if (!in_array($paymentEditorType, ['crypto', 'crypto_topup', 'bank'], true)) {
            $paymentEditorType = '';
        }
        if (!$bankTransfersVisibleInPayments && $paymentEditorType === 'bank') {
            $paymentEditorType = '';
        }
        $paymentEditorId = (int)($_POST['payment_id'] ?? $paymentEditorId);
        $paymentFilterCustomerId = max(0, (int)($_POST['customer_id'] ?? $paymentFilterCustomerId));
        $paymentScope = strtolower(trim((string)($_POST['payment_scope'] ?? $paymentScope)));
        if (!in_array($paymentScope, ['open', 'new', 'review', 'approved', 'archived', 'all'], true)) {
            $paymentScope = 'all';
        }
        $paymentTypeFilter = strtolower(trim((string)($_POST['payment_type_filter'] ?? $paymentTypeFilter)));
        if (!in_array($paymentTypeFilter, ['', 'crypto', 'bank'], true)) {
            $paymentTypeFilter = '';
        }
        if (!$cryptoPaymentsVisibleInPayments && $paymentTypeFilter === 'crypto') {
            $paymentTypeFilter = '';
        }
        if (!$bankTransfersVisibleInPayments && $paymentTypeFilter === 'bank') {
            $paymentTypeFilter = '';
        }

        if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
            $pageAlert = admin_t($messages, 'login_error', 'Login failed. Check your credentials.');
            $pageAlertType = 'danger';
        } elseif ($paymentEditorType === '') {
            $pageAlert = admin_t($messages, 'payment_bank_disabled_hidden', 'Bank transfer payments are currently hidden.');
            $pageAlertType = 'danger';
        } else {
            $quickActionResult = admin_payment_apply_quick_action(
                $db,
                $paymentEditorType,
                $paymentEditorId,
                (string)($_POST['quick_action'] ?? ''),
                (int)($adminUser['id'] ?? 0),
                $requestIp
            );

            if (!empty($quickActionResult['ok'])) {
                $quickAction = strtolower(trim((string)($_POST['quick_action'] ?? '')));
                if ($quickAction === 'accept' && (int)($quickActionResult['order_id'] ?? 0) > 0) {
                    $redirectUrl = '/admin/?page=orders&order_id=' . (int)$quickActionResult['order_id'];
                } elseif ($quickAction === 'renew' && !empty($quickActionResult['payment_type']) && (int)($quickActionResult['payment_id'] ?? 0) > 0) {
                    $redirectUrl = '/admin/?page=payments&payment_type=' . rawurlencode((string)$quickActionResult['payment_type']) . '&payment_id=' . (int)$quickActionResult['payment_id'] . '&renewed_payment=1';
                } else {
                    $redirectUrl = trim((string)($_POST['redirect_to'] ?? ''));
                    if ($redirectUrl === '') {
                        $redirectScope = $quickAction === 'review'
                            ? 'review'
                            : ($quickAction === 'archive' ? 'archived' : $paymentScope);
                        $redirectUrl = $buildPaymentsListUrl([
                            $quickAction === 'delete' ? 'deleted_payment' : 'saved_payment' => 1,
                            'payment_scope' => $redirectScope !== 'all' ? $redirectScope : null,
                        ]);
                    }
                }
                header('Location: ' . $redirectUrl);
                exit;
            }

            $pageAlert = (string)($quickActionResult['message'] ?? admin_t($messages, 'payment_save_error', 'Unable to save payment request.'));
            $pageAlertType = 'danger';
        }
    }

    if (isset($_POST['admin_save_payment'])) {
        $paymentEditorType = strtolower(trim((string)($_POST['payment_type'] ?? $paymentEditorType)));
        if (!in_array($paymentEditorType, ['crypto', 'crypto_topup', 'bank'], true)) {
            $paymentEditorType = '';
        }
        if (!$bankTransfersVisibleInPayments && $paymentEditorType === 'bank') {
            $paymentEditorType = '';
        }
        $paymentEditorId = (int)($_POST['payment_id'] ?? $paymentEditorId);
        $paymentFilterCustomerId = max(0, (int)($_POST['customer_id'] ?? $paymentFilterCustomerId));

        if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
            $pageAlert = admin_t($messages, 'login_error', 'Login failed. Check your credentials.');
            $pageAlertType = 'danger';
        } elseif ($paymentEditorType === '') {
            $pageAlert = admin_t($messages, 'payment_bank_disabled_hidden', 'Bank transfer payments are currently hidden.');
            $pageAlertType = 'danger';
        } else {
            $saveResult = admin_save_payment($db, $paymentEditorType, $paymentEditorId, $_POST, (int)($adminUser['id'] ?? 0), $requestIp);
            if (!empty($saveResult['ok'])) {
                $redirect = $buildPaymentsListUrl([
                    'payment_type' => $paymentEditorType,
                    'payment_id' => $paymentEditorId,
                    'saved_payment' => 1,
                ]);
                header('Location: ' . $redirect);
                exit;
            }

            $pageAlert = (string)($saveResult['message'] ?? admin_t($messages, 'payment_save_error', 'Unable to save payment request.'));
            $pageAlertType = 'danger';
        }
    }

    if (isset($_POST['admin_delete_payment'])) {
        $paymentEditorType = strtolower(trim((string)($_POST['payment_type'] ?? $paymentEditorType)));
        if (!in_array($paymentEditorType, ['crypto', 'crypto_topup', 'bank'], true)) {
            $paymentEditorType = '';
        }
        if (!$bankTransfersVisibleInPayments && $paymentEditorType === 'bank') {
            $paymentEditorType = '';
        }
        $paymentEditorId = (int)($_POST['payment_id'] ?? $paymentEditorId);
        $paymentFilterCustomerId = max(0, (int)($_POST['customer_id'] ?? $paymentFilterCustomerId));

        if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
            $pageAlert = admin_t($messages, 'login_error', 'Login failed. Check your credentials.');
            $pageAlertType = 'danger';
        } elseif ($paymentEditorType === '') {
            $pageAlert = admin_t($messages, 'payment_bank_disabled_hidden', 'Bank transfer payments are currently hidden.');
            $pageAlertType = 'danger';
        } else {
            $deleteResult = admin_delete_payment($db, $paymentEditorType, $paymentEditorId, (int)($adminUser['id'] ?? 0), $requestIp);
            if (!empty($deleteResult['ok'])) {
                $redirect = $buildPaymentsListUrl(['deleted_payment' => 1]);
                header('Location: ' . $redirect);
                exit;
            }

            $pageAlert = (string)($deleteResult['message'] ?? admin_t($messages, 'payment_delete_error', 'Unable to delete payment request.'));
            $pageAlertType = 'danger';
        }
    }

    if (isset($_POST['admin_delete_cancelled_payments'])) {
        $paymentFilterCustomerId = max(0, (int)($_POST['customer_id'] ?? $paymentFilterCustomerId));
        $paymentScope = strtolower(trim((string)($_POST['payment_scope'] ?? $paymentScope)));
        if (!in_array($paymentScope, ['open', 'new', 'review', 'approved', 'archived', 'all'], true)) {
            $paymentScope = 'all';
        }
        $paymentTypeFilter = strtolower(trim((string)($_POST['payment_type_filter'] ?? $paymentTypeFilter)));
        if (!in_array($paymentTypeFilter, ['', 'crypto', 'bank'], true)) {
            $paymentTypeFilter = '';
        }
        if (!$cryptoPaymentsVisibleInPayments && $paymentTypeFilter === 'crypto') {
            $paymentTypeFilter = '';
        }
        if (!$bankTransfersVisibleInPayments && $paymentTypeFilter === 'bank') {
            $paymentTypeFilter = '';
        }

        if (!admin_csrf_is_valid($_POST['_csrf'] ?? '')) {
            $pageAlert = admin_t($messages, 'login_error', 'Login failed. Check your credentials.');
            $pageAlertType = 'danger';
        } else {
            $deleteCancelledResult = admin_delete_cancelled_payments(
                $db,
                $paymentFilterCustomerId,
                $paymentTypeFilter,
                $bankTransfersVisibleInPayments,
                (int)($adminUser['id'] ?? 0),
                $requestIp
            );
            if (!empty($deleteCancelledResult['ok'])) {
                header('Location: ' . $buildPaymentsListUrl([
                    'deleted_cancelled_payments' => (int)($deleteCancelledResult['deleted_total'] ?? 0),
                ]));
                exit;
            }

            $pageAlert = (string)($deleteCancelledResult['message'] ?? admin_t($messages, 'payment_delete_error', 'Unable to delete payment request.'));
            $pageAlertType = 'danger';
        }
    }

    if ($paymentEditorType !== '' && $paymentEditorId > 0) {
        $paymentEditor = admin_payment_find($db, $paymentEditorType, $paymentEditorId);
        if (!$paymentEditor) {
            $paymentEditorType = '';
            $paymentEditorId = 0;
        } elseif (isset($_POST['admin_save_payment'])) {
            $paymentEditor = array_merge($paymentEditor, $_POST);
        }
    }
}

$navigation = admin_navigation_config($appSettings, $adminUser);
$assetVersion = admin_public_asset_version('assets/css/admin.css');
$scriptVersion = admin_public_asset_version('assets/js/admin.js');
$metrics = admin_dashboard_metrics($db);
$dashboardPeriodMetrics = admin_dashboard_period_metrics($db);
$dashboardSalesSeries = admin_dashboard_sales_series($db, 30);
$dashboardSalesSeriesPath = admin_dashboard_chart_path($dashboardSalesSeries);
$dashboardSalesSeriesPoints = admin_dashboard_chart_points($dashboardSalesSeries);
$dashboardChangeLogGroups = admin_dashboard_change_log_grouped_rows($db, 120);
